import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App";

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(<App />);

// iOS/Android standalone PWA can occasionally drop the first tap on inputs
// when the input sits inside animated/transformed panels. Keep focus tied to
// the user's tap so the software keyboard opens reliably from Home Screen.
const isStandalonePwa = () =>
  window.matchMedia?.("(display-mode: standalone)")?.matches ||
  window.navigator.standalone === true;

if (isStandalonePwa()) {
  const focusEditable = (event) => {
    const target = event.target?.closest?.("input, textarea, select");
    if (!target || target.disabled || target.readOnly) return;
    target.focus({ preventScroll: false });
  };
  document.addEventListener("touchend", focusEditable, true);
  document.addEventListener("pointerup", focusEditable, true);
}

// Register Service Worker for PWA (Add to Home Screen + Offline)
if ("serviceWorker" in navigator) {
  window.addEventListener("load", () => {
    const publicUrl = process.env.PUBLIC_URL || ".";
    const swUrl = `${publicUrl.replace(/\/$/, "")}/sw.js`;
    navigator.serviceWorker
      .register(swUrl)
      .catch(() => {});
  });
}
